 61→/// Make a JSON Schema node nullable by adding `"null"` to its type.
 62→///
 63→/// For schemas using `"type": "string"` (or any single type), this converts to
 64→/// `"type": ["string", "null"]`.  For schemas using `anyOf`/`oneOf`, it appends
 65→/// a `{"type": "null"}` variant.  Already-nullable schemas are left unchanged.
 66→fn make_nullable(schema: &mut serde_json::Value) {
 67→    let Some(obj) = schema.as_object_mut() else {
 68→        return;
 69→    };
 70→
 71→    // If it already has a "null" type, nothing to do.
 72→    if let Some(ty) = obj.get("type") {
 73→        if ty.as_str() == Some("null") {
 74→            return;
 75→        }
 76→        if let Some(arr) = ty.as_array()
 77→            && arr.iter().any(|v| v.as_str() == Some("null"))
 78→        {
 79→            return;
 80→        }
 81→    }
 82→
 83→    // Case 1: has a `type` field — convert to array form with "null".
 84→    if let Some(ty) = obj.get("type").cloned() {
 85→        if let Some(s) = ty.as_str() {
 86→            obj.insert("type".to_string(), serde_json::json!([s, "null"]));
 87→        } else if let Some(arr) = ty.as_array() {
 88→            let mut new_arr = arr.clone();
 89→            new_arr.push(serde_json::json!("null"));
 90→            obj.insert("type".to_string(), serde_json::Value::Array(new_arr));
 91→        }
 92→        return;
 93→    }
 94→
 95→    // Case 2: uses anyOf/oneOf — append a null variant.
 96→    for key in ["anyOf", "oneOf"] {
 97→        if let Some(variants) = obj.get_mut(key).and_then(|v| v.as_array_mut()) {
 98→            let has_null = variants
 99→                .iter()
100→                .any(|v| v.get("type").and_then(|t| t.as_str()) == Some("null"));
101→            if !has_null {
102→                variants.push(serde_json::json!({"type": "null"}));
103→            }
104→            return;
105→        }
106→    }
107→}
