2848→// ── Validation probe ordering ────────────────────────────────────────────────
2849→
2850→/// Reorder models so that known-fast, reliable models appear first for
2851→/// validation probing.  We only need *one* successful response to prove the
2852→/// API key works, so prefer the cheapest/fastest endpoints.
2853→fn reorder_models_for_validation(models: &mut [moltis_providers::ModelInfo]) {
2854→    /// Known-fast model substrings, ordered by preference.
2855→    /// These are small/cheap models that respond quickly on every major provider.
2856→    const FAST_PATTERNS: &[&str] = &[
2857→        "gpt-4o-mini",
2858→        "gpt-4.1-mini",
2859→        "gpt-4.1-nano",
2860→        "claude-3-haiku",
2861→        "claude-3.5-haiku",
2862→        "gemini-2.0-flash",
2863→        "gemini-flash",
2864→        "llama-3",
2865→        "mistral-small",
2866→        "deepseek-chat",
2867→    ];
2868→
2869→    /// Known-slow or experimental model substrings to deprioritize.
2870→    const SLOW_PATTERNS: &[&str] = &["search-preview", "seed-", "preview", "experimental"];
2871→
2872→    models.sort_by(|a, b| {
2873→        let a_rank = probe_priority_rank(&a.id, FAST_PATTERNS, SLOW_PATTERNS);
2874→        let b_rank = probe_priority_rank(&b.id, FAST_PATTERNS, SLOW_PATTERNS);
2875→        a_rank.cmp(&b_rank)
2876→    });
2877→}
