2879→fn probe_priority_rank(model_id: &str, fast: &[&str], slow: &[&str]) -> u8 {
2880→    let raw = raw_model_id(model_id);
2881→    for pattern in fast {
2882→        if raw.contains(pattern) {
2883→            return 0; // probe first
2884→        }
2885→    }
2886→    for pattern in slow {
2887→        if raw.contains(pattern) {
2888→            return 2; // probe last
2889→        }
2890→    }
2891→    1 // default: middle tier
2892→}
