 31→function progressFromPayload(payload) {
 32→	return {
 33→		total: payload?.total || 0,
 34→		checked: payload?.checked || 0,
 35→		supported: payload?.supported || 0,
 36→		unsupported: payload?.unsupported || 0,
 37→		errors: payload?.errors || 0,
 38→	};
