1694→                    .unwrap_or_default();
1695→                let model = models.first().cloned();
1696→
1697→                Some((
1698→                    offered_rank.get(&normalized_name).copied(),
1699→                    known_idx,
1700→                    serde_json::json!({
1701→                        "name": provider.name,
1702→                        "displayName": provider.display_name,
1703→                        "authType": provider.auth_type.as_str(),
1704→                        "configured": configured,
1705→                        "defaultBaseUrl": provider.default_base_url,
1706→                        "baseUrl": base_url,
1707→                        "models": models,
1708→                        "model": model,
