1726→            let base_url = config.base_url.clone();
1727→            let models = normalize_model_list(config.models.clone());
1728→            let model = models.first().cloned();
1729→
1730→            providers.push((
1731→                None,
1732→                known_count, // sort after all known providers
1733→                serde_json::json!({
1734→                    "name": name,
1735→                    "displayName": display_name,
1736→                    "authType": "api-key",
1737→                    "configured": true,
1738→                    "defaultBaseUrl": base_url,
1739→                    "baseUrl": base_url,
1740→                    "models": models,
1741→                    "model": model,
1742→                    "requiresModel": true,
1743→                    "keyOptional": false,
1744→                    "isCustom": true,
1745→                }),
