1747→        }
1748→
1749→        providers.sort_by(
1750→            |(a_offered, a_known, a_value), (b_offered, b_known, b_value)| {
1751→                let offered_cmp = match (a_offered, b_offered) {
1752→                    (Some(a), Some(b)) => a.cmp(b),
1753→                    (Some(_), None) => std::cmp::Ordering::Less,
1754→                    (None, Some(_)) => std::cmp::Ordering::Greater,
