1759→                }
1760→
1761→                let known_cmp = a_known.cmp(b_known);
1762→                if known_cmp != std::cmp::Ordering::Equal {
1763→                    return known_cmp;
1764→                }
1765→
1766→                let a_name = a_value
1767→                    .get("displayName")
1768→                    .and_then(|v| v.as_str())
1769→                    .unwrap_or_default();
1770→                let b_name = b_value
1771→                    .get("displayName")
1772→                    .and_then(|v| v.as_str())
1773→                    .unwrap_or_default();
1774→                a_name.cmp(b_name)
