1599→    /// Drain all pending discovery receivers (blocking on each `recv()`).
1600→    ///
1601→    /// Returns a map from provider name to discovered models.
1602→    pub fn collect_discoveries(
1603→        pending: PendingDiscoveries,
1604→    ) -> HashMap<String, Vec<DiscoveredModel>> {
1605→        let mut results: HashMap<String, Vec<DiscoveredModel>> = HashMap::new();
1606→        for (key, rx) in pending {
1607→            match rx.recv() {
1608→                Ok(Ok(models)) => {
1609→                    tracing::debug!(
1610→                        provider = %key,
1611→                        model_count = models.len(),
1612→                        "parallel model discovery succeeded"
1613→                    );
1614→                    results.insert(key, models);
1615→                },
1616→                Ok(Err(err)) => {
1617→                    let msg = err.to_string();
1618→                    if msg.contains("not logged in")
1619→                        || msg.contains("tokens not found")
1620→                        || msg.contains("not configured")
1621→                    {
1622→                        tracing::debug!(
1623→                            provider = %key,
1624→                            error = %err,
1625→                            "provider not configured, skipping model discovery"
1626→                        );
1627→                    } else {
1628→                        tracing::warn!(
1629→                            provider = %key,
1630→                            error = %err,
1631→                            "parallel model discovery failed"
1632→                        );
1633→                    }
1634→                },
1635→                Err(err) => {
1636→                    tracing::warn!(
1637→                        provider = %key,
1638→                        error = %err,
1639→                        "parallel model discovery worker crashed"
1640→                    );
1641→                },
1642→            }
1643→        }
1644→        results
1645→    }
