    #[test]
    fn resolve_ollama_tool_mode_explicit_override() {
        use moltis_config::ToolMode;
        // Explicit modes are passed through regardless of probe result.
        assert_eq!(
            resolve_ollama_tool_mode(ToolMode::Native, "anything", None),
