        assert_eq!(
            resolve_ollama_tool_mode(ToolMode::Auto, "llama3.1:8b", Some(&show_resp)),
            ToolMode::Text
        );
    }

    #[test]
    fn resolve_ollama_tool_mode_empty_capabilities_falls_back_to_family() {
